2	const httpProxy = require("http-proxy");
3	const { SERVICE_MAP } = require("../src/serviceMap");
4	const { attachInvokingIdentityHeaders } = require("../src/backendProxy");
5	
6	const router = express.Router();
7	
8	const proxy = httpProxy.createProxyServer({
9	  xfwd: true,
10	  proxyTimeout: 0,
11	  timeout: 0,
12	});
13	
14	proxy.on("error", (err, req, res) => {
15	  console.error("[BFF proxy error]", err?.message || err);
16	  if (res && !res.headersSent && typeof res.writeHead === "function") {
17	    res.writeHead(502, { "Content-Type": "application/json" });
18	    res.end(JSON.stringify({ error: "Bad gateway" }));
19	  }
20	});
21	
22	/**
23	 * /api/<service>/<backend-path>
24	 * Example: /api/core/getAllItems, /api/item_master/lib/getAllitems
25	 */
26	router.use(async (req, res) => {
27	  const pathname = req.path.replace(/^\//, "");
28	  const segments = pathname.split("/").filter(Boolean);
29	  const service = segments[0];
30	  const backendPath = segments.slice(1).join("/");
31	
32	  const backendUrl = SERVICE_MAP[service];
33	  if (!backendUrl) {
34	    return res.status(404).json({
35	      error: `Unknown backend service: ${service}`,
36	    });
37	  }
38	  if (!backendPath) {
39	    return res.status(404).json({ error: "Missing backend path" });
40	  }
41	
42	  const qIdx = req.url.indexOf("?");
43	  const search = qIdx !== -1 ? req.url.substring(qIdx) : "";
44	
45	  try {
46	    await attachInvokingIdentityHeaders(backendUrl, req);
47	    req.url = `/${backendPath}${search}`;
48	
49	    proxy.web(req, res, {
50	      target: backendUrl.replace(/\/$/, ""),
51	      changeOrigin: true,
52	    });
53	  } catch (err) {
54	    console.error(`[BFF ERROR] ${service} ${req.method} ${req.originalUrl}`, err.message);
55	    if (!res.headersSent) {
56	      res
57	        .status(err.response?.status || 500)
58	        .send(err.response?.data || { error: err.message || "Backend request failed" });
59	    }
60	  }
61	});
62	
63	module.exports = router;
